import 'package:shared_preferences/shared_preferences.dart';

import '../protocol/navivox_json.dart';
import 'saved_connection_fields.dart';

/// Persists non-secret gateway metadata for later reconnect flows.
///
/// Pairing handoff tokens are bootstrap-only and must not be stored here.
/// Silent reconnect remains disabled until a secure durable credential adapter
/// exists for the saved Gateway identity.
class SessionPersistenceService {
  static const _keyBaseUrl = 'navivox.session.base_url';
  static const _keyWebSocketUrl = 'navivox.session.websocket_url';
  static const _legacyKeyToken = 'navivox.session.token';
  static const _keyLastConnectedAt = 'navivox.session.last_connected_at';
  static const _keyGatewayId = 'navivox.session.gateway_id';

  SharedPreferences? _prefs;

  Future<void> ensureInitialized() async {
    if (_prefs != null) return;
    try {
      _prefs = await SharedPreferences.getInstance();
    } catch (_) {
      // SharedPreferences not available (e.g. test without mock).
    }
  }

  /// Save non-secret gateway metadata after a successful gateway connection.
  Future<void> saveConnection({
    required String baseUrl,
    String? webSocketUrl,
    String? gatewayId,
  }) async {
    await ensureInitialized();
    final prefs = _prefs;
    if (prefs == null) return;
    final fields = SavedConnectionFields.fromInput(
      baseUrl: baseUrl,
      webSocketUrl: webSocketUrl,
      gatewayId: gatewayId,
    );
    await prefs.setString(_keyBaseUrl, fields.baseUrl);
    await prefs.remove(_legacyKeyToken);
    if (fields.webSocketUrl != null) {
      await prefs.setString(_keyWebSocketUrl, fields.webSocketUrl!);
    } else {
      await prefs.remove(_keyWebSocketUrl);
    }
    if (fields.gatewayId != null) {
      await prefs.setString(_keyGatewayId, fields.gatewayId!);
    } else {
      await prefs.remove(_keyGatewayId);
    }
    await prefs.setString(
      _keyLastConnectedAt,
      DateTime.now().toUtc().toIso8601String(),
    );
  }

  /// Load saved connection state. Returns null if no session is saved.
  Future<SavedSession?> loadSession() async {
    await ensureInitialized();
    final prefs = _prefs;
    if (prefs == null) return null;
    final baseUrl = navivoxOptionalStringFromJson(prefs.getString(_keyBaseUrl));
    if (baseUrl == null) return null;

    return SavedSession(
      baseUrl: baseUrl,
      webSocketUrl: navivoxOptionalStringFromJson(
        prefs.getString(_keyWebSocketUrl),
      ),
      gatewayId: navivoxOptionalStringFromJson(prefs.getString(_keyGatewayId)),
      lastConnectedAt: navivoxDateTimeFromJson(
        prefs.getString(_keyLastConnectedAt),
      ),
    );
  }

  /// Remove saved session. Call when user explicitly disconnects,
  /// or when reconnect fails with an expired/revoked credential.
  Future<void> clearSession() async {
    await ensureInitialized();
    final prefs = _prefs;
    if (prefs == null) return;
    await prefs.remove(_keyBaseUrl);
    await prefs.remove(_legacyKeyToken);
    await prefs.remove(_keyWebSocketUrl);
    await prefs.remove(_keyLastConnectedAt);
    await prefs.remove(_keyGatewayId);
  }

  /// Check if a saved session exists without loading all fields.
  Future<bool> hasSession() async {
    await ensureInitialized();
    final prefs = _prefs;
    if (prefs == null) return false;
    final baseUrl = prefs.getString(_keyBaseUrl);
    return baseUrl != null && baseUrl.trim().isNotEmpty;
  }
}

class SavedSession {
  const SavedSession({
    required this.baseUrl,
    this.webSocketUrl,
    this.gatewayId,
    this.lastConnectedAt,
  });

  final String baseUrl;
  final String? webSocketUrl;
  final String? gatewayId;
  final DateTime? lastConnectedAt;

  /// Whether the session is stale (no recent connection).
  bool get isStale {
    if (lastConnectedAt == null) return true;
    return DateTime.now().toUtc().difference(lastConnectedAt!).inDays > 7;
  }

  /// Whether this metadata can currently perform silent reconnect.
  ///
  /// This remains false until a secure durable credential adapter exists.
  bool get canAttemptReconnect => false;
}

import 'saved_connection_fields.dart';

void main() {
  saveConnectionFieldsClearBlankOptionalValues();
}

void saveConnectionFieldsClearBlankOptionalValues() {
  final fields = SavedConnectionFields.fromInput(
    baseUrl: ' https://gateway.example/api ',
    webSocketUrl: '   ',
    gatewayId: null,
  );

  _expect(
    fields.baseUrl == 'https://gateway.example/api',
    'base URL is trimmed',
  );
  _expect(
    fields.webSocketUrl == null,
    'blank websocket URL must clear stale persisted websocket metadata',
  );
  _expect(
    fields.gatewayId == null,
    'absent gateway id must clear stale persisted gateway metadata',
  );
}

void _expect(bool condition, String message) {
  if (!condition) throw StateError(message);
}

import '../protocol/navivox_json.dart';

class SavedConnectionFields {
  const SavedConnectionFields({
    required this.baseUrl,
    this.webSocketUrl,
    this.gatewayId,
  });

  factory SavedConnectionFields.fromInput({
    required String baseUrl,
    String? webSocketUrl,
    String? gatewayId,
  }) {
    return SavedConnectionFields(
      baseUrl: baseUrl.trim(),
      webSocketUrl: navivoxOptionalStringFromJson(webSocketUrl),
      gatewayId: navivoxOptionalStringFromJson(gatewayId),
    );
  }

  final String baseUrl;
  final String? webSocketUrl;
  final String? gatewayId;
}

class GatewayCredentialMetadata {
  const GatewayCredentialMetadata({
    required this.gatewayId,
    required this.appInstallIdentity,
    required this.credentialLabel,
    required this.createdAt,
    this.lastUsedAt,
  });

  final String gatewayId;
  final String appInstallIdentity;
  final String credentialLabel;
  final DateTime createdAt;
  final DateTime? lastUsedAt;

  bool get isUsableMetadata {
    return gatewayId.trim().isNotEmpty &&
        appInstallIdentity.trim().isNotEmpty &&
        credentialLabel.trim().isNotEmpty;
  }
}

abstract interface class DurableCredentialStore {
  Future<bool> containsCredential({required String gatewayId});

  Future<GatewayCredentialMetadata?> metadata({required String gatewayId});

  Future<void> deleteCredential({required String gatewayId});
}

class EmptyDurableCredentialStore implements DurableCredentialStore {
  const EmptyDurableCredentialStore();

  @override
  Future<bool> containsCredential({required String gatewayId}) async => false;

  @override
  Future<GatewayCredentialMetadata?> metadata({
    required String gatewayId,
  }) async => null;

  @override
  Future<void> deleteCredential({required String gatewayId}) async {}
}

import '../gateway/navivox_gateway_protocol.dart';
import '../protocol/navivox_json.dart';

class ReconnectReadiness {
  const ReconnectReadiness({
    required this.kind,
    required this.message,
    this.recoveryMessage,
  });

  factory ReconnectReadiness.fromCapabilities(
    NavivoxCapabilityDocument? capabilities,
  ) {
    if (capabilities == null) {
      return const ReconnectReadiness(
        kind: ReconnectReadinessKind.unknown,
        message: 'Checking reconnect support…',
      );
    }
    final durable = capabilities.durableReconnect;
    return switch (durable.readinessKind) {
      ReconnectReadinessKind.unsupported => const ReconnectReadiness(
        kind: ReconnectReadinessKind.unsupported,
        message: 'Reconnect cannot be saved for this gateway yet.',
        recoveryMessage:
            'Connected for this app session. Pair again after restart if needed.',
      ),
      ReconnectReadinessKind.blocked => ReconnectReadiness(
        kind: ReconnectReadinessKind.blocked,
        message: 'Reconnect cannot be saved on this connection.',
        recoveryMessage: navivoxOptionalStringFromJson(durable.blockedReason),
      ),
      ReconnectReadinessKind.available => const ReconnectReadiness(
        kind: ReconnectReadinessKind.available,
        message: 'Reconnect support is available but not saved yet.',
      ),
      ReconnectReadinessKind.unknown => const ReconnectReadiness(
        kind: ReconnectReadinessKind.unknown,
        message: 'Checking reconnect support…',
      ),
      ReconnectReadinessKind.saved => const ReconnectReadiness(
        kind: ReconnectReadinessKind.saved,
        message: 'Reconnect saved for this gateway.',
      ),
    };
  }

  final ReconnectReadinessKind kind;
  final String message;
  final String? recoveryMessage;
}

import 'dart:convert';
import 'package:crypto/crypto.dart';
import 'package:flutter/services.dart';

import '../protocol/navivox_json.dart';

class DurableCredentialKeyAlias {
  const DurableCredentialKeyAlias.native(this.value);

  factory DurableCredentialKeyAlias.forGatewayInstall({
    required String gatewayId,
    required String appInstallIdentity,
  }) {
    final gateway = gatewayId.trim();
    final install = appInstallIdentity.trim();
    if (gateway.isEmpty || install.isEmpty) {
      throw ArgumentError(
        'Gateway identity and app install identity are required.',
      );
    }
    final digest = sha256.convert(utf8.encode('$gateway\u0000$install'));
    return DurableCredentialKeyAlias.native('navivox_durable_$digest');
  }

  final String value;

  @override
  String toString() => value;
}

class PublicJsonWebKey {
  const PublicJsonWebKey({
    required this.kty,
    required this.crv,
    required this.x,
    required this.y,
    required this.alg,
    this.kid,
  });

  factory PublicJsonWebKey.fromJson(Map<Object?, Object?> json) {
    return PublicJsonWebKey(
      kty: _requiredString(json, 'kty'),
      crv: _requiredString(json, 'crv'),
      x: _requiredString(json, 'x'),
      y: _requiredString(json, 'y'),
      alg: _requiredString(json, 'alg'),
      kid: _optionalString(json, 'kid'),
    );
  }

  final String kty;
  final String crv;
  final String x;
  final String y;
  final String alg;
  final String? kid;

  Map<String, Object?> toJson() => {
    'kty': kty,
    'crv': crv,
    'x': x,
    'y': y,
    'alg': alg,
    if (kid != null) 'kid': kid,
  };

  static String _requiredString(Map<Object?, Object?> json, String key) {
    final value = navivoxOptionalLiteralStringFromJson(json[key]);
    if (value == null) {
      throw FormatException('Missing public JWK field: $key');
    }
    return value;
  }

  static String? _optionalString(Map<Object?, Object?> json, String key) {
    return navivoxOptionalLiteralStringFromJson(json[key]);
  }
}

abstract interface class DurableCredentialKeyStore {
  Future<bool> isAvailable();

  Future<PublicJsonWebKey> createEs256KeyPair({
    required DurableCredentialKeyAlias alias,
  });

  Future<Uint8List> sign({
    required DurableCredentialKeyAlias alias,
    required Uint8List canonicalPayload,
  });

  Future<void> deleteKey({required DurableCredentialKeyAlias alias});
}

class MethodChannelDurableCredentialKeyStore
    implements DurableCredentialKeyStore {
  const MethodChannelDurableCredentialKeyStore({
    MethodChannel channel = const MethodChannel(_channelName),
  }) : _channel = channel;

  static const _channelName = 'com.trebuchetdynamics.navivox/durable_keys';

  final MethodChannel _channel;

  @override
  Future<bool> isAvailable() async {
    try {
      return await _channel.invokeMethod<bool>('isAvailable') ?? false;
    } on MissingPluginException {
      return false;
    } on PlatformException {
      return false;
    }
  }

  @override
  Future<PublicJsonWebKey> createEs256KeyPair({
    required DurableCredentialKeyAlias alias,
  }) async {
    final result = await _channel.invokeMethod<Object?>('createEs256KeyPair', {
      'alias': alias.value,
    });
    if (result is! Map) {
      throw const FormatException(
        'Native key store did not return a public JWK.',
      );
    }
    return PublicJsonWebKey.fromJson(result);
  }

  @override
  Future<Uint8List> sign({
    required DurableCredentialKeyAlias alias,
    required Uint8List canonicalPayload,
  }) async {
    final result = await _channel.invokeMethod<Uint8List>('signEs256', {
      'alias': alias.value,
      'canonicalPayload': canonicalPayload,
    });
    if (result == null || result.isEmpty) {
      throw const FormatException(
        'Native key store did not return a signature.',
      );
    }
    return result;
  }

  @override
  Future<void> deleteKey({required DurableCredentialKeyAlias alias}) async {
    await _channel.invokeMethod<void>('deleteKey', {'alias': alias.value});
  }
}

/// Shared coercion helpers for Navivox wire-protocol JSON payloads.
///
/// These helpers intentionally accept loose `Object?` values because gateway and
/// memory endpoints can be decoded from typed maps, platform channels, or JSON
/// maps with dynamic keys.
String navivoxStringFromJson(Object? value, {required String fallback}) {
  final text = value?.toString().trim();
  if (text == null || text.isEmpty) return fallback;
  return text;
}

String? navivoxOptionalStringFromJson(Object? value) {
  final text = value?.toString().trim();
  if (text == null || text.isEmpty) return null;
  return text;
}

/// Returns a trimmed string only when [value] is already a literal string.
String? navivoxOptionalLiteralStringFromJson(Object? value) {
  if (value is! String) return null;
  final text = value.trim();
  return text.isEmpty ? null : text;
}

int navivoxIntFromJson(Object? value) {
  if (value is int) return value;
  if (value is num) return value.toInt();
  return int.tryParse(value?.toString() ?? '') ?? 0;
}

double? navivoxDoubleFromJson(Object? value) {
  if (value is double) return value;
  if (value is num) return value.toDouble();
  return double.tryParse(value?.toString() ?? '');
}

bool navivoxBoolFromJson(Object? value, {bool fallback = false}) {
  if (value is bool) return value;
  final text = value?.toString().trim().toLowerCase();
  if (text == 'true' || text == '1' || text == 'yes') return true;
  if (text == 'false' || text == '0' || text == 'no') return false;
  return fallback;
}

/// Returns only literal bool values or `true`/`false` string tokens.
///
/// Use this for protocol flags whose existing contract intentionally does not
/// accept broader truthy aliases such as `1` or `yes`.
bool navivoxStrictBoolFromJson(Object? value, {bool fallback = false}) {
  if (value is bool) return value;
  final text = value?.toString().trim().toLowerCase();
  if (text == 'true') return true;
  if (text == 'false') return false;
  return fallback;
}

Map<String, Object?> navivoxMapFromJson(Object? value) {
  if (value is! Map) return const {};
  return Map<String, Object?>.from(value);
}

Map<String, Object?> navivoxMapFieldFromJson(
  Map<String, Object?> json,
  String key,
) {
  return navivoxMapFromJson(json[key]);
}

List<Object?> navivoxListFromJson(Object? value) {
  if (value is! List) return const [];
  return value.cast<Object?>();
}

/// Returns map entries from a loose wire list, ignoring non-map items.
List<Map<String, Object?>> navivoxMapListFromJson(Object? value) {
  return navivoxListFromJson(
    value,
  ).whereType<Map>().map(navivoxMapFromJson).toList(growable: false);
}

List<Object?> navivoxListFieldFromJson(Map<String, Object?> json, String key) {
  return navivoxListFromJson(json[key]);
}

List<String> navivoxStringListFromJson(Object? value) {
  if (value is! List) return const [];
  return navivoxTrimmedStringList(value);
}

String navivoxStringFieldFromJson(Map<String, Object?> json, String key) {
  return navivoxStringFromJson(json[key], fallback: '');
}

/// Selects a typed enum/value object by matching its wire value.
///
/// The wire token uses the same non-empty trimmed string semantics as other
/// Navivox protocol fields and falls back when the value is blank or unknown.
T navivoxValueFromWire<T>({
  required Object? value,
  required Iterable<T> values,
  required String Function(T value) wireValue,
  required T fallback,
}) {
  final text = navivoxOptionalStringFromJson(value);
  if (text == null) return fallback;
  for (final candidate in values) {
    if (wireValue(candidate) == text) return candidate;
  }
  return fallback;
}

/// Returns the first non-empty literal string field whose key matches [names].
///
/// The lookup first honors exact keys, then falls back to a compatibility match
/// that ignores underscores and case so wire payloads can use either
/// `snake_case` or `camelCase` aliases without each parser reimplementing that
/// policy. Non-string values are intentionally ignored to preserve strict wire
/// semantics for IDs, URLs, and tokens.
String? navivoxFirstStringFieldFromJson(
  Map<dynamic, dynamic> json,
  Iterable<String> names,
) {
  for (final name in names) {
    final exact = navivoxOptionalLiteralStringFromJson(json[name]);
    if (exact != null) return exact;
  }
  final normalizedNames = {
    for (final name in names) _navivoxNormalizeJsonFieldName(name),
  };
  for (final entry in json.entries) {
    if (!normalizedNames.contains(
      _navivoxNormalizeJsonFieldName('${entry.key}'),
    )) {
      continue;
    }
    final value = navivoxOptionalLiteralStringFromJson(entry.value);
    if (value != null) return value;
  }
  return null;
}

String _navivoxNormalizeJsonFieldName(String value) =>
    value.toLowerCase().replaceAll('_', '');

List<String> navivoxStringListFieldFromJson(
  Map<String, Object?> json,
  String key,
) {
  return navivoxStringListFromJson(json[key]);
}

/// Returns non-empty trimmed string values in their original order.
List<String> navivoxTrimmedStringList(Iterable<Object?> values) {
  return values
      .map((item) => item.toString().trim())
      .where((item) => item.isNotEmpty)
      .toList(growable: false);
}

/// Returns a string map with null/blank values removed and remaining values
/// trimmed. Useful for query params and wire request bodies that share Navivox
/// non-empty string field semantics.
Map<String, String> navivoxTrimmedStringFields(Map<String, Object?> values) {
  return {
    for (final entry in values.entries)
      if (entry.value case final value?)
        if (value.toString().trim().isNotEmpty)
          entry.key: value.toString().trim(),
  };
}

/// Returns a query-parameter map using the first non-empty value for each key.
///
/// This keeps copied URLs with duplicate blank parameters from erasing the
/// earlier value supplied by the producer.
Map<String, String> navivoxFirstNonBlankQueryParameterValues(
  Map<String, List<String>> queryParametersAll,
) {
  final result = <String, String>{};
  for (final entry in queryParametersAll.entries) {
    final value = navivoxFirstNonBlankQueryParameterValue(entry.value);
    if (value != null) result[entry.key] = value;
  }
  return result;
}

String? navivoxFirstNonBlankQueryParameterValue(List<String> values) {
  for (final value in values) {
    final text = navivoxOptionalLiteralStringFromJson(value);
    if (text != null) return text;
  }
  return null;
}

DateTime? navivoxDateTimeFromJson(Object? value) {
  final text = value?.toString().trim();
  if (text == null || text.isEmpty) return null;
  return DateTime.tryParse(text);
}

import '../serialization/navivox_json.dart';

/// URI normalization helpers shared by Navivox pairing and setup flows.
const navivoxEndpointSchemes = {'http', 'https', 'ws', 'wss'};

bool navivoxIsEndpointScheme(String scheme) {
  return navivoxEndpointSchemes.contains(scheme.trim().toLowerCase());
}

String navivoxHttpSchemeFromEndpointScheme(
  String scheme, {
  String? descriptor,
}) {
  return switch (scheme.trim().toLowerCase()) {
    'ws' => 'http',
    'wss' => 'https',
    'http' => 'http',
    'https' => 'https',
    _ => throw FormatException(
      'Navivox endpoint URI must use ws, wss, http, or https',
      descriptor,
    ),
  };
}

String navivoxOriginFromUri(Uri uri) {
  return _navivoxOrigin(
    scheme: uri.scheme,
    host: uri.host,
    explicitPort: uri.hasPort ? uri.port : null,
  );
}

String _navivoxOrigin({
  required String scheme,
  required String host,
  required int? explicitPort,
}) {
  final formattedHost = host.contains(':') ? '[$host]' : host;
  final formattedPort = explicitPort == null ? '' : ':$explicitPort';
  return '$scheme://$formattedHost$formattedPort';
}

String navivoxHttpBaseUrlFromEndpointUri(Uri uri, {String? descriptor}) {
  final scheme = navivoxHttpSchemeFromEndpointScheme(
    uri.scheme,
    descriptor: descriptor,
  );
  if (uri.host.isEmpty) {
    throw FormatException(
      'Navivox endpoint URI must include a host',
      descriptor,
    );
  }
  return _navivoxOrigin(
    scheme: scheme,
    host: uri.host,
    explicitPort: uri.hasPort ? uri.port : null,
  );
}

String? navivoxHttpOriginOrOriginalFromString(String? raw) {
  final value = navivoxOptionalStringFromJson(raw);
  if (value == null) return null;
  final uri = Uri.tryParse(value);
  if (uri == null || !uri.hasScheme || uri.host.isEmpty) return value;
  final scheme = uri.scheme.toLowerCase();
  if (scheme != 'http' && scheme != 'https') return value;
  return navivoxOriginFromUri(uri);
}

Uri navivoxWebSocketUriFromEndpointString(String raw, {String? descriptor}) {
  final uri = Uri.parse(raw);
  if (uri.host.isEmpty) {
    throw FormatException(
      'Navivox websocket URI must include a host',
      descriptor,
    );
  }
  final scheme = uri.scheme.toLowerCase();
  if (scheme != 'ws' && scheme != 'wss') {
    throw FormatException(
      'Navivox websocket URI must use ws or wss',
      descriptor,
    );
  }
  return uri;
}

String? navivoxWebSocketUrlFromEndpointString(String? raw) {
  final value = navivoxOptionalStringFromJson(raw);
  if (value == null) return null;
  try {
    return navivoxWebSocketUriFromEndpointString(value).toString();
  } on FormatException {
    return null;
  }
}

String? navivoxHttpBaseUrlFromEndpointString(String? raw) {
  final uri = _endpointUriFromString(raw);
  if (uri == null || !navivoxIsEndpointScheme(uri.scheme)) return null;
  return navivoxHttpBaseUrlFromEndpointUri(uri);
}

Uri? _endpointUriFromString(String? raw) {
  final value = navivoxOptionalStringFromJson(raw);
  if (value == null) return null;
  final uri = Uri.tryParse(value);
  if (uri == null || !uri.hasScheme || uri.host.isEmpty) return null;
  return uri;
}

import 'navivox_endpoint_uri.dart';

void main() {
  derivesHttpOriginFromWebSocketEndpointWithoutDroppingExplicitPort();
  stripsPathAndQueryOnlyForHttpBaseUrlDerivation();
  preservesWebSocketPathAndQueryForConnectionEndpoint();
  keepsOriginalValueWhenHttpOriginCannotBeDerived();
}

void derivesHttpOriginFromWebSocketEndpointWithoutDroppingExplicitPort() {
  final result = navivoxHttpBaseUrlFromEndpointString(
    'wss://gateway.example:443/navivox/ws?token=secret',
  );

  _expect(
    result == 'https://gateway.example:443',
    'explicit default ports are part of the endpoint origin contract',
  );
}

void stripsPathAndQueryOnlyForHttpBaseUrlDerivation() {
  final result = navivoxHttpBaseUrlFromEndpointString(
    'https://gateway.example:8443/api?token=secret',
  );

  _expect(result == 'https://gateway.example:8443', 'base URL is origin only');
}

void preservesWebSocketPathAndQueryForConnectionEndpoint() {
  final result = navivoxWebSocketUrlFromEndpointString(
    'wss://gateway.example/navivox/ws?token=secret',
  );

  _expect(
    result == 'wss://gateway.example/navivox/ws?token=secret',
    'websocket endpoint keeps path/query while base URL derivation strips them',
  );
}

void keepsOriginalValueWhenHttpOriginCannotBeDerived() {
  final result = navivoxHttpOriginOrOriginalFromString(
    'ftp://gateway.example/resource',
  );

  _expect(
    result == 'ftp://gateway.example/resource',
    'non-HTTP values are preserved for compatibility instead of rejected',
  );
}

void _expect(bool condition, String message) {
  if (!condition) throw StateError(message);
}

import 'dart:convert';

import '../shared/navivox_gateway_json.dart';
import 'navivox_gateway_event.dart';

/// Decodes one raw WebSocket event payload into the typed gateway event model.
///
/// The gateway stream can deliver already-decoded objects in tests/adapters or
/// JSON strings from real sockets. Invalid payloads are normalized to the same
/// typed error event so clients do not duplicate wire-shape checks.
NavivoxGatewayEvent navivoxGatewayEventFromWire(Object? event) {
  final object = navivoxGatewayObjectFromWireEvent(event);
  if (!_isValidGatewayEventObject(object)) return navivoxInvalidGatewayEvent();
  return NavivoxGatewayEvent.fromJson(object!);
}

/// Converts one loose WebSocket payload into a decoded event object.
///
/// This intentionally returns `null` for malformed JSON, non-object JSON, and
/// non-map adapter payloads so callers can preserve the gateway client's
/// bad-response event contract without leaking parser exceptions.
Map<String, Object?>? navivoxGatewayObjectFromWireEvent(Object? event) {
  final decoded = _navivoxDecodedWireEvent(event);
  return navivoxGatewayOptionalObjectFromJson(decoded);
}

bool _isValidGatewayEventObject(Map<String, Object?>? object) {
  return object != null && navivoxGatewayHasText(object['type']);
}

NavivoxGatewayEvent navivoxInvalidGatewayEvent() {
  return const NavivoxGatewayEvent(
    type: 'error',
    code: 'bad_response',
    message: 'Invalid gateway event',
  );
}

Object? _navivoxDecodedWireEvent(Object? event) {
  if (event is! String) return event;
  try {
